INSERT INTO Movies (movie_id, title, release_year, duration, language, synopsis, poster_url, trailer_url, avg_rating, total_ratings) VALUES (103, 'Katyar Kaljat Ghusali', 2015, 162, 'Marathi', 'Katyar Kaljat Ghusli is a 2015 Marathi film based on a play by the same name. Directed by Subodh Bhave, the film stars Sachin Pilgaonkar, Shankar Mahadevan, and Subodh Bhave in lead roles. The film marks the acting debut for Mahadevan and directorial debut for Bhave. The original play premiered in 1967 in Mumbai, where Hindustani classical vocalist Vasantrao Deshpande played one of the protagonists. In 2010, the play was relaunched with protagonists essayed by Rahul Deshpande, grandson of Vasantrao Deshpande and singer Mahesh Kale. The film\'s music is composed by Shankar���Ehsaan���Loy, and retained some of the songs from the original play composed by Jitendra Abhisheki.', 'https://image.tmdb.org/t/p/w500/vbpvvVX8EwzDSB6qjoCoiirvSMt.jpg', '', 4.45, 9) ON DUPLICATE KEY UPDATE title=VALUES(title);
