INSERT INTO Movies (movie_id, title, release_year, duration, language, synopsis, poster_url, trailer_url, avg_rating, total_ratings) VALUES (200, 'Andrei Rublev', 1966, 183, 'ru', 'An expansive Russian drama, this film focuses on the life of revered religious icon painter Andrei Rublev. Drifting from place to place in a tumultuous era, the peace-seeking monk eventually gains a reputation for his art. But after Rublev witnesses a brutal battle and unintentionally becomes involved, he takes a vow of silence and spends time away from his work. As he begins to ease his troubled soul, he takes steps towards becoming a painter once again.', 'https://image.tmdb.org/t/p/w500/910xRIUmNJrWH2hkQifBJtoPp5R.jpg', '', 4, 941) ON DUPLICATE KEY UPDATE title=VALUES(title);
