INSERT INTO Movies (movie_id, title, release_year, duration, language, synopsis, poster_url, trailer_url, avg_rating, total_ratings) VALUES (205, 'Circus of Life', 2020, 144, 'Punjabi', 'A devout Muslim who writes, composes, and even records hymns praising the Prophet, Muhammad Rahat Khawaja is a respected elderly man who works in real estate and takes care of his bedridden wife. One day, he attends the wedding of a friend\'s son, where he inadvertently shows off a dance in front of his friends and family. His dance gets recorded and then uploaded to all social media platforms, which then also gets broadcasted on television. And chaos begins to ensue in his quiet life. Other than his wife, no one else in the world understands Rahat\'s circumstances. His daughters and neighbors criticize him, his friends turn their backs on him', 'https://image.tmdb.org/t/p/w500/in9zaAGE9aIw0DKtagJvsfqkknl.jpg', '', 4, 11) ON DUPLICATE KEY UPDATE title=VALUES(title);
