INSERT INTO Movies (movie_id, title, release_year, duration, language, synopsis, poster_url, trailer_url, avg_rating, total_ratings) VALUES (223, 'Office Romance', 1977, NULL, 'ru', 'Anatoly Novoseltsev is a mousy single father and office stumblebum working at a statistics bureau in Moscow. In the hopes of being promoted, he is coaxed into charming his disagreeable and seemingly unfeeling boss, Ludmila Kalugina, or "Meany" as she\'s otherwise known by her subordinates. Helped by his colleagues Olya and Yura, Anatoly attempts to ease the yoke of Ms. Kalugina, and what follows in the wake of his graceless manoeuvres is completely unforeseen, as he awakens a side to her not yet known, even to herself..', 'https://image.tmdb.org/t/p/w500/21TgZRiA5gDlyCwQEyYqZcqwMgN.jpg', '', 3.95, 262) ON DUPLICATE KEY UPDATE title=VALUES(title);
