INSERT INTO Movies (movie_id, title, release_year, duration, language, synopsis, poster_url, trailer_url, avg_rating, total_ratings) VALUES (477, 'The Silence', 2015, 97, 'Marathi', 'Late at night on a local train in Mumbai, young Chini witnesses a woman being sexually abused. This experience forces her to face up to demons from her past. Based on a true story, the narrative revolves around a little girl growing up in poverty with her father in a rural area. When he���s unable to manage caring for her himself, he sends Chini to her uncle in a nearby town, where life-changing events occur. Blending past and present and with forceful drama, the film tackles crucial, taboo topics, tracing the recurring question of responsibility ��� or silence.', 'https://image.tmdb.org/t/p/w500/eZ7S8gt9hrMGUJZ0BdqwYj769si.jpg', '', 3.6, 7) ON DUPLICATE KEY UPDATE title=VALUES(title);
