INSERT INTO Movies (movie_id, title, release_year, duration, language, synopsis, poster_url, trailer_url, avg_rating, total_ratings) VALUES (897, 'Cosmic Sex', 2015, 96, 'Bengali', 'Cosmic Sex is a 2014 art-house Independent Bengali Film written and directed by Amitabh Chakraborty and produced by Putul Mahmood. The film deals with the connection between Sex and Spirituality.Cosmic Sex is the story of a young man Kripa who is on the run from sex and violence one night in Kolkata when he meets a woman Sadhavi who strangely resembles his dead mother. She gives him shelter and teaches him to travel inwards through sex. The film deals with Dehotatva (worshipping through one���s own body) and explores the connection between Sex and Spirituality. The film stars Rii Sen who won the best actress award at Osian\'s Cinefan Festival of Asian and Arab Cinema for her bold act in the movie.[', 'https://image.tmdb.org/t/p/w500/gh8UoQd8PJOelIOY5ng9VMOmrS1.jpg', '', 3.05, 33) ON DUPLICATE KEY UPDATE title=VALUES(title);
