INSERT INTO Movies (movie_id, title, release_year, duration, language, synopsis, poster_url, trailer_url, avg_rating, total_ratings) VALUES (916, 'JUJUTSU KAISEN: Execution', 2025, 88, 'ja', 'A veil abruptly descends over the busy Shibuya area amid the bustling Halloween crowds, trapping countless civilians inside. Satoru Gojo, the strongest jujutsu sorcerer, steps into the chaos. But lying in wait are curse users and spirits scheming to seal him away. Yuji Itadori, accompanied by his classmates and other top-tier jujutsu sorcerers, enters the fray in an unprecedented clash of curses ��� the Shibuya Incident. In the aftermath, ten colonies across Japan are transformed into dens of curses in a plan orchestrated by Noritoshi Kamo. As the deadly Culling Game starts, Special Grade sorcerer Yuta Okkotsu is assigned to carry out Yuji\'s execution for his perceived crimes. A compilation movie of Shibuya Incident including the first two episodes of the Culling Games arc.', 'https://image.tmdb.org/t/p/w500/v0s3dx6am0RzfsuK3KdEy8ZoCDs.jpg', '', 3, 98) ON DUPLICATE KEY UPDATE title=VALUES(title);
