INSERT INTO Movies (movie_id, title, release_year, duration, language, synopsis, poster_url, trailer_url, avg_rating, total_ratings) VALUES (1017, 'After Porn Ends 2', 2017, 90, 'en', 'After Porn Ends 2 picks up where its predecessor left off and not only turns back the clock to meet the oldest living stars in adult film\'s history, but goes in depth with some of Its most current retirees and juxtaposes their experiences in a life after porn. Delving deeper into society\'s ongoing stigmas of race, misogyny, and the reality of decreasing opportunities for these former VHS box cover stars. For some, their careers in adult entertainment is accepted proudly and without regret. In fact, it seems to have proven to be the pathway to their current happiness and inner peace. For others, however, a career in porn has proven to be a conduit to certain despair as they struggle to find a way to bury their past and emerge with a new career or calling.', 'https://image.tmdb.org/t/p/w500/rfItXrtDGILwsCdmgVxX79phFuI.jpg', '', 2.7, 251) ON DUPLICATE KEY UPDATE title=VALUES(title);
