INSERT INTO Movies (movie_id, title, release_year, duration, language, synopsis, poster_url, trailer_url, avg_rating, total_ratings) VALUES (1127, 'Dispassionate Love', 2018, 91, 'Bengali', 'Recalling memories of a friend who committed suicide, three lovers slowly slide into an anguish labyrinth of desire, loss and longing. They entangle in a colliding maze of forsaken loves, failed expectations and imperfect anticipations. A disintegrating web arises in which love exists, but as dispassionate yearning. Here affection is an indifferent desire that burns the soul to death.', 'https://image.tmdb.org/t/p/w500/bAERtg7tDuWjppFKFLnpxpqf5Tp.jpg', '', 1.65, 6) ON DUPLICATE KEY UPDATE title=VALUES(title);
INSERT IGNORE INTO Movie_Genres (movie_id, genre_id) SELECT 1127, genre_id FROM Genres WHERE genre_name='Drama';
INSERT INTO Movies (movie_id, title, release_year, duration, language, synopsis, poster_url, trailer_url, avg_rating, total_ratings) VALUES (1128, 'Band Vaaje', 2019, NULL, 'Punjabi', 'Inder meets Bilkis and develops an instant liking for her and sets out to woo her, not realizing that Bilkis is from Pakistan. His grandmother\'s hatred of Pakistanis forces him to lie to his family that she is not from Pakistan.', 'https://image.tmdb.org/t/p/w500/hPYHdwngtxRcnMpv0pc56Lm0iT3.jpg', '', 1.65, 6) ON DUPLICATE KEY UPDATE title=VALUES(title);
INSERT IGNORE INTO Movie_Genres (movie_id, genre_id) SELECT 1128, genre_id FROM Genres WHERE genre_name='Drama';
INSERT IGNORE INTO Movie_Genres (movie_id, genre_id) SELECT 1128, genre_id FROM Genres WHERE genre_name='Comedy';
INSERT INTO Movies (movie_id, title, release_year, duration, language, synopsis, poster_url, trailer_url, avg_rating, total_ratings) VALUES (1129, 'Ludo', 2015, 90, 'Bengali', 'Needing a secluded place for a late-night tryst, two couples stow away in a mall after hours, but are quickly ensnared in a gruesome and deadly game.', 'https://image.tmdb.org/t/p/w500/rso6tCy4IZOcjckDQdRdPciWHfw.jpg', '', 1.5, 50) ON DUPLICATE KEY UPDATE title=VALUES(title);
